//! Persistent guarded moonshine REPL.
//!
//! The per-command cost of the fire-and-forget path is dominated by
//! monster-guard: each command pays ~700ms for two process spawns
//! (`delegate` then `run`), each doing UCAN crypto. moonshine itself executes
//! `echo` in well under 1ms warm.
//!
//! This module pays that guard cost ONCE: it keeps a single
//! `monster-guard run -- moonshine` process alive in interactive mode and feeds
//! commands over stdin. Per-command latency then collapses to stdin-write +
//! stdout-read — sub-millisecond for trivial commands.
//!
//! ## Output correlation
//!
//! moonshine streams all output to one stdout, so we need to know where one
//! command's output ends. After writing the user command we write a second
//! line: `echo <SENTINEL><id>`. The reader task accumulates lines until it sees
//! that exact sentinel line, at which point the command is complete. The
//! sentinel uses a UUID so user output can't collide with it.

use anyhow::{anyhow, Result};
use std::collections::HashMap;
use std::path::Path;
use std::process::Stdio;
use std::sync::Arc;
use tauri::Emitter;
use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
use tokio::process::{Child, ChildStdin, Command};
use tokio::sync::{mpsc, Mutex, RwLock};
use uuid::Uuid;

/// True if a line of REPL output should be suppressed as startup banner noise.
///
/// The "moonshine — Monster On Shell In Engine (The FRF Shell)" title line is
/// pure chrome and is ALWAYS dropped — that's the line we're targeting. The
/// rest of the banner (`Identity: did:...`, the `Type 'exit'...` hint) is
/// useful for debugging, so it's shown only when MOONSHINE_BANNER=1 (or
/// =true); by default it's off too, keeping the pane clean.
pub fn is_moonshine_banner(line: &str) -> bool {
    let t = line.trim_start();
    // Always strip the title — it adds nothing.
    if t.starts_with("moonshine — Monster On Shell In Engine")
        || t.starts_with("☾☽ Moonshine — Monster On Shell In Engine")
    {
        return true;
    }
    // The informational lines are debug-gated: off by default, shown when
    // MOONSHINE_BANNER is set truthy.
    let debug_banner = std::env::var("MOONSHINE_BANNER")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false);
    if debug_banner {
        return false;
    }
    // The grey "[moonshine] sourced ~/.rc: N aliases, M exports" line is printed
    // once at startup (in ANSI \x1b[90m…, so trim_start won't expose its head —
    // match by substring). It lands on the first command's output otherwise.
    if t.contains("[moonshine] sourced ~/") && t.contains(" exports") {
        return true;
    }
    t.starts_with("Identity: did:") || t.starts_with("Type 'exit' or Ctrl-D to quit")
}

/// Scrollback bound for a single command's output. The buffer keeps roughly the
/// last OUTPUT_CAP bytes and is only re-sliced once it runs OUTPUT_SLACK past
/// the cap (amortizing the trim cost over many lines).
const OUTPUT_CAP: usize = 256 * 1024;
const OUTPUT_SLACK: usize = 64 * 1024;

/// A line of output routed to a waiting command, tagged with completion.
struct ReplLine {
    line: String,
    done: bool,
    exit_code: Option<i32>,
}

/// Live state for an in-flight or completed command.
#[derive(Default)]
struct CommandState {
    output: String,
    done: bool,
    exit_code: Option<i32>,
    /// Wall-clock execution time in milliseconds, set when the command finishes.
    duration_ms: Option<u64>,
}

/// A persistent guarded moonshine REPL.
pub struct PersistentRepl {
    stdin: Arc<Mutex<ChildStdin>>,
    /// Sentinel prefix unique to this REPL session.
    sentinel: String,
    /// Per-command channels: command id → receiver sink. The reader task looks
    /// up the *current* command id (commands are serialized) to route lines.
    current: Arc<Mutex<Option<mpsc::UnboundedSender<ReplLine>>>>,
    /// Persisted state per command id, so the frontend can poll output even
    /// after completion. Source of truth.
    states: Arc<RwLock<HashMap<String, CommandState>>>,
    /// Serializes command submission (one command in flight at a time).
    submit_lock: Arc<Mutex<()>>,
    _child: Arc<Mutex<Child>>,
}

impl PersistentRepl {
    /// Spawn the guarded moonshine process with a fresh command history.
    pub async fn spawn(
        guard_bin: &str,
        guard_home: &str,
        moonshine_bin: &str,
        app: tauri::AppHandle,
    ) -> Result<Self> {
        Self::spawn_with_states(
            guard_bin,
            guard_home,
            moonshine_bin,
            app,
            Arc::new(RwLock::new(HashMap::new())),
        )
        .await
    }

    /// Kill the underlying moonshine process. The reader tasks then see EOF on
    /// the closed pipes and exit on their own. Used before a restart.
    pub async fn shutdown(&self) {
        let mut child = self._child.lock().await;
        let _ = child.start_kill();
    }

    /// Recover from a wedged REPL (e.g. a non-interactive command that never
    /// returns and so blocks moonshine itself): kill the old process, mark any
    /// still-running command as interrupted (exit 130), and spawn a fresh
    /// moonshine that REUSES the command-history map so completed output/scroll
    /// back survives the restart.
    pub async fn restart(
        &self,
        guard_bin: &str,
        guard_home: &str,
        moonshine_bin: &str,
        app: tauri::AppHandle,
    ) -> Result<Self> {
        self.shutdown().await;
        {
            let mut st = self.states.write().await;
            for s in st.values_mut() {
                if !s.done {
                    s.done = true;
                    s.exit_code = Some(130);
                }
            }
        }
        // Stop routing to any task waiting on the (now dead) old process.
        *self.current.lock().await = None;
        Self::spawn_with_states(guard_bin, guard_home, moonshine_bin, app, self.states.clone()).await
    }

    /// Spawn the guarded moonshine process, reusing the given command-history
    /// map. The reader tasks start immediately.
    async fn spawn_with_states(
        guard_bin: &str,
        guard_home: &str,
        moonshine_bin: &str,
        app: tauri::AppHandle,
        states: Arc<RwLock<HashMap<String, CommandState>>>,
    ) -> Result<Self> {
        let session_name = format!("moonshine-repl-{}", Uuid::new_v4());

        // Delegate capabilities once for the whole session.
        let extra_path = bundled_tool_path(moonshine_bin);
        let mut delegate_cmd = Command::new(guard_bin);
        delegate_cmd
            .env("MONSTER_GUARD_HOME", guard_home)
            .env("MOONSHINE_EXTRA_PATH", &extra_path);
        if let Ok(tokens) = std::env::var("MOONSHINE_AGENT_GEN_TOKENS") {
            delegate_cmd.env("MOONSHINE_AGENT_GEN_TOKENS", tokens);
        }
        let delegate = delegate_cmd
            .args(["delegate", &session_name, "fs,net,exec", "--ttl", "86400"])
            .output()
            .await?;
        if !delegate.status.success() {
            return Err(anyhow!(
                "delegate failed: {}",
                String::from_utf8_lossy(&delegate.stderr)
            ));
        }

        // Launch the long-lived guarded interactive moonshine.
        let mut child_cmd = Command::new(guard_bin);
        let initial_cwd = home::home_dir()
            .or_else(|| std::env::current_dir().ok())
            .unwrap_or_else(|| std::path::PathBuf::from("/"));
        child_cmd
            .env("MONSTER_GUARD_HOME", guard_home)
            .env("MOONSHINE_EXTRA_PATH", &extra_path)
            .env("PATH", child_path_with_tools(&extra_path));
        if let Ok(tokens) = std::env::var("MOONSHINE_AGENT_GEN_TOKENS") {
            child_cmd.env("MOONSHINE_AGENT_GEN_TOKENS", tokens);
        }
        let mut child = child_cmd
            .args([
                "run",
                "--name",
                &session_name,
                "--caps",
                "fs,net,exec",
                "--lease",
                "86400",
                "--",
                moonshine_bin,
            ])
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .current_dir(initial_cwd)
            .kill_on_drop(true)
            .spawn()?;

        let stdin = child.stdin.take().ok_or_else(|| anyhow!("no stdin"))?;
        let stdout = child.stdout.take().ok_or_else(|| anyhow!("no stdout"))?;
        let stderr = child.stderr.take().ok_or_else(|| anyhow!("no stderr"))?;

        let sentinel = format!("__MOONSHINE_DONE_{}__", Uuid::new_v4().simple());
        let current: Arc<Mutex<Option<mpsc::UnboundedSender<ReplLine>>>> =
            Arc::new(Mutex::new(None));

        // stdout reader: detects the sentinel to mark completion.
        Self::spawn_reader(stdout, sentinel.clone(), current.clone(), true, app.clone());
        // stderr reader: routes lines too, but never carries the sentinel.
        Self::spawn_reader(stderr, sentinel.clone(), current.clone(), false, app);

        Ok(PersistentRepl {
            stdin: Arc::new(Mutex::new(stdin)),
            sentinel,
            current,
            states,
            submit_lock: Arc::new(Mutex::new(())),
            _child: Arc::new(Mutex::new(child)),
        })
    }

    fn spawn_reader<R>(
        pipe: R,
        sentinel: String,
        current: Arc<Mutex<Option<mpsc::UnboundedSender<ReplLine>>>>,
        is_stdout: bool,
        _app: tauri::AppHandle,
    ) where
        R: tokio::io::AsyncRead + Unpin + Send + 'static,
    {
        tokio::spawn(async move {
            let reader = BufReader::new(pipe);
            let mut lines = reader.lines();
            while let Ok(Some(line)) = lines.next_line().await {
                // Suppress moonshine's interactive startup banner — it clutters
                // the top of every session and adds nothing. (No --quiet flag
                // upstream, so we filter the distinctive lines here.)
                if is_moonshine_banner(&line) {
                    continue;
                }
                // The sentinel only ever appears on stdout (we write it as an
                // echo). Detect it and signal completion. moonshine does NOT
                // expand `$?`, so the sentinel carries no code; exit status is
                // inferred from moonshine's own failure line (see below).
                if is_stdout && line.trim() == sentinel {
                    if let Some(tx) = current.lock().await.as_ref() {
                        let _ = tx.send(ReplLine {
                            line: String::new(),
                            done: true,
                            exit_code: None,
                        });
                    }
                    continue;
                }
                // moonshine prints `[moonshine] command failed: <cmd> (exit
                // code: Some(N))` on a non-zero exit. Parse N as the exit code.
                let parsed_code = if line.contains("[moonshine] command failed")
                    || line.contains("command failed:")
                {
                    line.rsplit("Some(")
                        .next()
                        .and_then(|s| s.split(')').next())
                        .and_then(|s| s.trim().parse::<i32>().ok())
                        .or(Some(1))
                } else {
                    None
                };
                if let Some(tx) = current.lock().await.as_ref() {
                    let _ = tx.send(ReplLine {
                        line: line.clone(),
                        done: false,
                        exit_code: parsed_code,
                    });
                }
                // NOTE: shell:output is emitted from submit() (per command), where
                // the command id is known — the frontend filters events by
                // process_id, so emitting here (no id) would never match.
            }
        });
    }

    /// Submit a command, returning the command id immediately. Output streams
    /// into the persisted state, readable via `get_state`.
    pub async fn submit(&self, command: &str, app: &tauri::AppHandle) -> Result<String> {
        let cmd_id = Uuid::new_v4().to_string();
        self.states
            .write()
            .await
            .insert(cmd_id.clone(), CommandState::default());

        let (tx, mut rx) = mpsc::unbounded_channel::<ReplLine>();

        // Take the submit lock so only one command is in flight; route lines.
        let submit_lock = self.submit_lock.clone();
        let stdin = self.stdin.clone();
        let current = self.current.clone();
        let states = self.states.clone();
        let sentinel = self.sentinel.clone();
        let command = command.to_string();
        let cmd_id_task = cmd_id.clone();
        let app = app.clone();

        tokio::spawn(async move {
            let _guard = submit_lock.lock().await;
            *current.lock().await = Some(tx);

            // Start the clock once we actually own the REPL and are about to
            // write (excludes time spent queued behind another command).
            let started = std::time::Instant::now();

            // Write the command, then a bare sentinel echo so we know when its
            // output ends. moonshine doesn't expand `$?`, so exit status is
            // inferred from any "command failed" line seen before the sentinel.
            {
                let mut si = stdin.lock().await;
                let payload = format!("{}\necho {}\n", command, sentinel);
                if si.write_all(payload.as_bytes()).await.is_err() {
                    let mut st = states.write().await;
                    if let Some(s) = st.get_mut(&cmd_id_task) {
                        s.done = true;
                        s.exit_code = None;
                    }
                    return;
                }
                let _ = si.flush().await;
            }

            // Accumulate routed lines until the sentinel. A success leaves
            // last_code None (treated as 0); a failure line sets it to N.
            let mut last_code: Option<i32> = None;
            while let Some(item) = rx.recv().await {
                if let Some(code) = item.exit_code {
                    last_code = Some(code);
                }
                if item.done {
                    let final_code = last_code.or(Some(0));
                    let elapsed = started.elapsed().as_millis() as u64;
                    let mut st = states.write().await;
                    if let Some(s) = st.get_mut(&cmd_id_task) {
                        s.done = true;
                        s.exit_code = final_code;
                        s.duration_ms = Some(elapsed);
                    }
                    let _ = app.emit(
                        "shell:exit",
                        serde_json::json!({ "process_id": cmd_id_task, "exit_code": final_code, "duration_ms": elapsed }),
                    );
                    break;
                } else if !item.line.is_empty()
                    && !item.line.contains("[moonshine] command failed")
                {
                    // The exit code from moonshine's synthetic
                    // "[moonshine] command failed: <cmd> (exit code: Some(N))"
                    // line was already captured into last_code above; the red
                    // ✗N exit pill now conveys it, so we drop the raw line from
                    // the output (a failing `false` shows nothing, like a real
                    // shell) instead of leaking moonshine's internal phrasing.
                    {
                        let mut st = states.write().await;
                        if let Some(s) = st.get_mut(&cmd_id_task) {
                            s.output.push_str(&item.line);
                            s.output.push('\n');
                            // Bound the scrollback: a command with huge output
                            // (seq, find /, yes) would otherwise grow the buffer
                            // unbounded AND ship the whole thing over IPC every
                            // poll. Keep the last OUTPUT_CAP bytes, trimmed at a
                            // line boundary. Amortized: only re-slice once we're
                            // OUTPUT_SLACK past the cap, so it's not O(n²).
                            if s.output.len() > OUTPUT_CAP + OUTPUT_SLACK {
                                let cut = s.output.len() - OUTPUT_CAP;
                                let b = s.output.as_bytes();
                                let mut c = cut;
                                while c < s.output.len() && b[c] != b'\n' {
                                    c += 1;
                                }
                                if c < s.output.len() {
                                    c += 1; // past the newline (ASCII = char boundary)
                                }
                                s.output = format!("…(earlier output trimmed)…\n{}", &s.output[c..]);
                            }
                        }
                    }
                    // Live fast-path: tag the line with the command id so the
                    // frontend's shell:output listener (which filters by
                    // process_id) can refresh immediately instead of waiting for
                    // the 250ms poll.
                    let _ = app.emit(
                        "shell:output",
                        serde_json::json!({ "process_id": cmd_id_task, "line": item.line }),
                    );
                }
            }
            *current.lock().await = None;
        });

        Ok(cmd_id)
    }

    /// Read the persisted (output, done, exit_code, duration_ms) for a command.
    pub async fn get_state(&self, cmd_id: &str) -> Option<(String, bool, Option<i32>, Option<u64>)> {
        self.states
            .read()
            .await
            .get(cmd_id)
            .map(|s| (s.output.clone(), s.done, s.exit_code, s.duration_ms))
    }

    /// Drop the stored output of every finished command, reclaiming the memory.
    /// In-flight commands (not yet done) are kept so a running command isn't lost.
    pub async fn clear_finished(&self) {
        self.states.write().await.retain(|_, s| !s.done);
    }
}

fn bundled_tool_path(moonshine_bin: &str) -> String {
    Path::new(moonshine_bin)
        .parent()
        .map(|path| path.to_string_lossy().into_owned())
        .unwrap_or_default()
}

fn child_path_with_tools(extra_path: &str) -> String {
    let inherited = std::env::var("PATH").unwrap_or_default();
    let mut parts = Vec::new();
    if !extra_path.is_empty() {
        parts.push(extra_path.to_string());
    }
    if let Some(user_bin) = home::home_dir()
        .map(|home| home.join(".local/bin"))
        .filter(|path| path.is_dir())
    {
        parts.push(user_bin.to_string_lossy().into_owned());
    }
    if !inherited.is_empty() {
        parts.push(inherited);
    }
    parts.join(":")
}
